#!/usr/bin/env node
/**
 * Build the Electron installer with code signing.
 *
 * Loads CSC_LINK and CSC_KEY_PASSWORD from build/private/codesign.env
 * (gitignored), then runs electron-builder. The env file is generated by
 * scripts/generate-codesign-cert.ps1.
 *
 * Safety gates (applied in order):
 *   1. Fail fast if signing env is missing, unless ADSI_ALLOW_UNSIGNED=1.
 *      Unsigned installers cannot auto-update existing signed installs
 *      because electron-updater rejects publisher-hash mismatches.
 *   2. Post-build signature verification via Get-AuthenticodeSignature.
 *      Confirms the file was actually signed (electron-builder can silently
 *      skip signing on timestamp-server errors) and pins the thumbprint to
 *      build/private/codesign-thumbprint.txt so a stray cert can't ship.
 *   3. Installer size floor + SHA-512 log. Rejects builds that are
 *      implausibly small (missing Python services, broken extraResources)
 *      and logs the SHA-512 that electron-updater will expect in latest.yml.
 *
 * Usage:
 *   node scripts/build-installer-signed.js
 *   npm run build:installer:signed
 *
 * Dev escape hatch:
 *   ADSI_ALLOW_UNSIGNED=1 node scripts/build-installer-signed.js
 */

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { spawnSync } = require('child_process');

const repoRoot = path.resolve(__dirname, '..');
const envFile = path.join(repoRoot, 'build', 'private', 'codesign.env');
const thumbFile = path.join(repoRoot, 'build', 'private', 'codesign-thumbprint.txt');
const verifyScript = path.join(repoRoot, 'scripts', 'verify-signed-installer.ps1');
const releaseDir = path.join(repoRoot, 'release');

const ALLOW_UNSIGNED = process.env.ADSI_ALLOW_UNSIGNED === '1';
// 300 MB floor — historical builds are ~500-620 MB. A broken build
// missing the Python services EXE would be well under 100 MB.
const MIN_INSTALLER_BYTES = 300 * 1024 * 1024;

const env = { ...process.env };
let signed = false;

if (fs.existsSync(envFile)) {
  const content = fs.readFileSync(envFile, 'utf8');
  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith('#')) continue;
    const eq = line.indexOf('=');
    if (eq < 0) continue;
    const key = line.slice(0, eq).trim();
    const value = line.slice(eq + 1).trim();
    if (key) env[key] = value;
  }

  // CSC_LINK in the env file is repo-relative; resolve to absolute path so
  // electron-builder finds it regardless of cwd.
  if (env.CSC_LINK && !path.isAbsolute(env.CSC_LINK)) {
    env.CSC_LINK = path.resolve(repoRoot, env.CSC_LINK);
  }

  if (env.CSC_LINK && env.CSC_KEY_PASSWORD && fs.existsSync(env.CSC_LINK)) {
    signed = true;
    console.log('[build-installer-signed] Code signing enabled');
    console.log('[build-installer-signed]   PFX:', env.CSC_LINK);
  } else {
    console.warn('[build-installer-signed] Env file present but PFX missing or invalid:');
    console.warn('  CSC_LINK         =', env.CSC_LINK || '(unset)');
    console.warn('  CSC_KEY_PASSWORD =', env.CSC_KEY_PASSWORD ? '(set)' : '(unset)');
  }
} else {
  console.warn('[build-installer-signed] Code signing env file missing:', envFile);
  console.warn('[build-installer-signed] Run: powershell -ExecutionPolicy Bypass -File scripts/generate-codesign-cert.ps1');
}

// ─── GATE 1: Require signing unless explicitly opted out ────────────────────
if (!signed) {
  if (!ALLOW_UNSIGNED) {
    console.error('');
    console.error('[build-installer-signed] FATAL: code signing is required for release builds.');
    console.error('  Either:');
    console.error('    (a) provision build/private/codesign.env with a valid PFX + password, or');
    console.error('    (b) set ADSI_ALLOW_UNSIGNED=1 to build an unsigned installer for dev/testing.');
    console.error('');
    console.error('  Unsigned installers CANNOT auto-update existing signed installations');
    console.error('  because electron-updater rejects publisher-hash mismatches.');
    process.exit(1);
  }
  console.warn('[build-installer-signed] ADSI_ALLOW_UNSIGNED=1 — proceeding with UNSIGNED build');
  delete env.CSC_LINK;
  delete env.CSC_KEY_PASSWORD;
}

// ─── electron-builder ───────────────────────────────────────────────────────
const args = ['electron-builder', '--win', 'nsis', '--x64'];
console.log('[build-installer-signed] Running: npx', args.join(' '));

const result = spawnSync('npx', args, {
  cwd: repoRoot,
  stdio: 'inherit',
  env,
  shell: true,
});

if (result.error) {
  console.error('[build-installer-signed] Failed to spawn electron-builder:', result.error.message);
  process.exit(1);
}
if (result.status !== 0) {
  console.error('[build-installer-signed] electron-builder exited with status', result.status);
  process.exit(result.status || 1);
}

// ─── Locate the built installer ─────────────────────────────────────────────
function findInstaller() {
  if (!fs.existsSync(releaseDir)) return null;
  const files = fs.readdirSync(releaseDir);
  const setup = files.find((f) => /^Inverter-Dashboard-Setup-.*\.exe$/i.test(f));
  if (setup) return path.join(releaseDir, setup);
  // Fallback: any "*Setup*.exe" in release/
  const generic = files.find((f) => /setup.*\.exe$/i.test(f));
  return generic ? path.join(releaseDir, generic) : null;
}

const installerPath = findInstaller();
if (!installerPath) {
  console.error('[build-installer-signed] FATAL: could not locate built installer in', releaseDir);
  process.exit(1);
}
console.log('');
console.log('[build-installer-signed] Installer:', installerPath);

// ─── GATE 2: Post-build signature verification ──────────────────────────────
if (signed) {
  const expectedThumb = fs.existsSync(thumbFile)
    ? fs.readFileSync(thumbFile, 'utf8').trim().toUpperCase()
    : '';

  if (!fs.existsSync(verifyScript)) {
    console.error('[build-installer-signed] FATAL: verification script missing:', verifyScript);
    process.exit(1);
  }

  const psArgs = [
    '-NoProfile',
    '-ExecutionPolicy', 'Bypass',
    '-File', verifyScript,
    '-Path', installerPath,
  ];
  if (expectedThumb) {
    psArgs.push('-ExpectedThumbprint', expectedThumb);
  }

  console.log('[build-installer-signed] Verifying signature…');
  const verify = spawnSync('powershell.exe', psArgs, {
    cwd: repoRoot,
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  const stdout = (verify.stdout || '').toString().trim();
  const stderr = (verify.stderr || '').toString().trim();
  stdout.split(/\r?\n/).filter(Boolean).forEach((line) => console.log('  ' + line));

  if (verify.status !== 0) {
    console.error('[build-installer-signed] FATAL: signature verification FAILED (exit=' + verify.status + ')');
    if (stderr) {
      stderr.split(/\r?\n/).filter(Boolean).forEach((line) => console.error('  ' + line));
    }
    console.error('  electron-builder may have silently skipped signing.');
    console.error('  Check its output above for timestamp server errors, expired cert, or missing signtool.');
    process.exit(1);
  }

  if (!expectedThumb) {
    console.warn('[build-installer-signed] WARNING: build/private/codesign-thumbprint.txt missing —');
    console.warn('                           thumbprint pin check was skipped.');
  }
}

// ─── GATE 3: Installer size floor + SHA-512 log ─────────────────────────────
const stat = fs.statSync(installerPath);
const sizeMB = (stat.size / (1024 * 1024)).toFixed(1);
console.log('');
console.log('[build-installer-signed] Installer size: ' + stat.size + ' bytes (' + sizeMB + ' MB)');

if (stat.size < MIN_INSTALLER_BYTES) {
  const floorMB = (MIN_INSTALLER_BYTES / (1024 * 1024)).toFixed(0);
  console.error(
    '[build-installer-signed] FATAL: installer is only ' + sizeMB + ' MB, below ' + floorMB + ' MB floor.',
  );
  console.error('  Historical releases are ~500-620 MB. This build is likely missing the');
  console.error('  Python services EXE or other bundled assets. Do NOT upload.');
  process.exit(1);
}

// Compute SHA-512 (the hash electron-updater will expect in latest.yml).
// Stream to avoid loading 620 MB into memory.
const hash = crypto.createHash('sha512');
const stream = fs.createReadStream(installerPath);
stream.on('data', (chunk) => hash.update(chunk));
stream.on('end', () => {
  const digest = hash.digest('base64');
  console.log('[build-installer-signed] SHA-512 (base64): ' + digest);
  console.log('');
  console.log('[build-installer-signed] Build OK — ready for upload');
  process.exit(0);
});
stream.on('error', (err) => {
  console.error('[build-installer-signed] Failed to compute SHA-512:', err.message);
  process.exit(1);
});
